// ── Demo Cursor ──────────────────────────────────────────────────
function DemoCursor({ controllerRef, containerRef }) {
  const [pos, setPos] = useState({ x: 353, y: 200 });
  const [targetPos, setTargetPos] = useState({ x: 353, y: 200 });
  const [mode, setMode] = useState("pointer");
  const [visible, setVisible] = useState(false);
  const [clicks, setClicks] = useState([]);
  const animRef = useRef(null);
  const currentPos = useRef({ x: 353, y: 200 });

  const moveTo = useCallback((x, y, duration = 800) => {
    return new Promise(resolve => {
      const startX = currentPos.current.x;
      const startY = currentPos.current.y;
      const startTime = performance.now();
      if (animRef.current) cancelAnimationFrame(animRef.current);
      const animate = (now) => {
        const elapsed = now - startTime;
        const t = Math.min(elapsed / duration, 1);
        const ease = t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;

        const rect = containerRef.current?.getBoundingClientRect() || { left: 0, top: 0 };
        const relX = x - rect.left;
        const relY = y - rect.top;

        const cx = startX + (relX - startX) * ease;
        const cy = startY + (relY - startY) * ease;
        currentPos.current = { x: cx, y: cy };
        setPos({ x: cx, y: cy });
        if (t < 1) { animRef.current = requestAnimationFrame(animate); }
        else { currentPos.current = { x: relX, y: relY }; setPos({ x: relX, y: relY }); resolve(); }
      };
      animRef.current = requestAnimationFrame(animate);
    });
  }, []);

  const click = useCallback((x, y) => {
    const rect = containerRef.current?.getBoundingClientRect() || { left: 0, top: 0 };
    const relX = x - rect.left;
    const relY = y - rect.top;
    const id = Date.now();
    setClicks(c => [...c, { id, x: relX, y: relY }]);
    setTimeout(() => setClicks(c => c.filter(cl => cl.id !== id)), 500);
  }, [containerRef]);

  useEffect(() => {
    if (controllerRef) {
      controllerRef.current = {
        moveTo,
        click,
        setMode: (m) => setMode(m),
        show: () => setVisible(true),
        hide: () => setVisible(false),
      };
    }
    return () => { if (animRef.current) cancelAnimationFrame(animRef.current); };
  }, [controllerRef, moveTo, click]);

  if (!visible) return null;
  return (
    <>
      <div style={{ position: "absolute", left: pos.x, top: pos.y, pointerEvents: "none", zIndex: 9999 }}>
        {mode === "pointer" && (
          <svg width="20" height="24" viewBox="0 0 20 24" fill="none">
            <path d="M3 2 L3 19 L7 15 L10 22 L12.5 21 L9.5 14 L15 14 Z" fill="white" stroke="#1a1a1a" strokeWidth="0.8" />
          </svg>
        )}
        {mode === "crosshair" && (
          <svg width="24" height="24" viewBox="0 0 24 24" style={{ filter: "drop-shadow(0 0 4px rgba(234,88,12,0.7))", transform: "translate(-12px,-12px)" }}>
            <line x1="12" y1="2" x2="12" y2="10" stroke="#ea580c" strokeWidth="1.5" />
            <line x1="12" y1="14" x2="12" y2="22" stroke="#ea580c" strokeWidth="1.5" />
            <line x1="2" y1="12" x2="10" y2="12" stroke="#ea580c" strokeWidth="1.5" />
            <line x1="14" y1="12" x2="22" y2="12" stroke="#ea580c" strokeWidth="1.5" />
            <rect x="10" y="10" width="4" height="4" stroke="#ea580c" strokeWidth="1" fill="none" />
          </svg>
        )}
      </div>
      {clicks.map(c => (
        <motion.div key={c.id}
          initial={{ scale: 1, opacity: 0.8, width: 6, height: 6 }}
          animate={{ scale: 10, opacity: 0 }}
          transition={{ duration: 0.45, ease: "easeOut" }}
          style={{ position: "absolute", left: c.x - 3, top: c.y - 3, border: "1px solid #ea580c", pointerEvents: "none", zIndex: 9998 }}
        />
      ))}
    </>
  );
}

// ── Ring Canvas ──────────────────────────────────────────────────
function RingCanvas({ numRings = 12, animated = true, delayBetweenRings = 80, showCounter = false, showPith = false, canvasSize = 280, startDelay = 0, className = "" }) {
  const canvasRef = useRef(null);
  const stateRef = useRef({ completedRings: 0, currentProgress: 0, animFrame: null, started: false });

  function generateOrganicRing(cx, cy, radius, numPoints, ringIndex) {
    const seed = ringIndex * 137.508;
    const points = [];
    for (let i = 0; i < numPoints; i++) {
      const angle = (i / numPoints) * Math.PI * 2;
      const v = 1 + 0.055 * Math.sin(angle * 3 + seed * 0.1)
        + 0.035 * Math.sin(angle * 7 + seed * 0.07)
        + 0.02 * Math.sin(angle * 13 + seed * 0.03);
      const r = radius * v * (1 + ringIndex * 0.008);
      points.push([cx + Math.cos(angle) * r, cy + Math.sin(angle) * r]);
    }
    return points;
  }

  function ringColor(index, total) {
    const hue = (50 + (index / total) * 300) % 360;
    return `hsl(${hue}, 88%, 62%)`;
  }

  function drawFrame(canvas, ctx, dpr, size, completedRings, currentRingProgress, t) {
    ctx.clearRect(0, 0, size, size);
    const cx = size / 2, cy = size / 2;
    const maxR = size * 0.44;
    const step = maxR / (numRings + 1);

    for (let i = 0; i < completedRings; i++) {
      const radius = step * (i + 1);
      const pts = generateOrganicRing(cx, cy, radius, 120, i);
      const color = ringColor(i, numRings);
      ctx.beginPath();
      ctx.moveTo(pts[0][0], pts[0][1]);
      for (let j = 1; j < pts.length; j++) ctx.lineTo(pts[j][0], pts[j][1]);
      ctx.closePath();
      ctx.strokeStyle = color;
      ctx.lineWidth = 1.2;
      ctx.shadowBlur = 4;
      ctx.shadowColor = color;
      ctx.stroke();
      ctx.shadowBlur = 0;
    }

    if (completedRings < numRings && currentRingProgress > 0) {
      const i = completedRings;
      const radius = step * (i + 1);
      const pts = generateOrganicRing(cx, cy, radius, 120, i);
      const endIdx = Math.floor(pts.length * currentRingProgress);
      const color = ringColor(i, numRings);
      ctx.beginPath();
      ctx.moveTo(pts[0][0], pts[0][1]);
      for (let j = 1; j < endIdx; j++) ctx.lineTo(pts[j][0], pts[j][1]);
      ctx.strokeStyle = color;
      ctx.lineWidth = 1.2;
      ctx.shadowBlur = 6;
      ctx.shadowColor = color;
      ctx.stroke();
      ctx.shadowBlur = 0;
    }

    if (showPith) {
      const pulse = 4 + Math.sin(t / 800) * 2;
      ctx.beginPath();
      ctx.arc(cx, cy, pulse, 0, Math.PI * 2);
      ctx.fillStyle = "#ea580c";
      ctx.shadowBlur = 16;
      ctx.shadowColor = "#ea580c";
      ctx.fill();
      ctx.shadowBlur = 0;
    }

    if (showCounter) {
      ctx.font = `bold 9px var(--font-jetbrains), monospace`;
      ctx.fillStyle = "#ea580c";
      ctx.shadowBlur = 6;
      ctx.shadowColor = "#ea580c";
      ctx.fillText(`RINGS: ${String(completedRings).padStart(2, "0")}`, size - 68, 16);
      ctx.shadowBlur = 0;
    }

    for (let y = 0; y < size; y += 3) {
      ctx.fillStyle = "rgba(0,0,0,0.05)";
      ctx.fillRect(0, y, size, 1);
    }
  }

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    canvas.width = canvasSize * dpr;
    canvas.height = canvasSize * dpr;
    canvas.style.width = canvasSize + "px";
    canvas.style.height = canvasSize + "px";
    const ctx = canvas.getContext("2d");
    ctx.scale(dpr, dpr);

    if (!animated) {
      for (let i = 0; i <= numRings; i++) stateRef.current.completedRings = i;
      drawFrame(canvas, ctx, dpr, canvasSize, numRings, 0, 0);
      return;
    }

    let cancelled = false;
    let completedRings = 0;
    let ringProgress = 0;
    let lastRingTime = null;
    const ringDuration = Math.max(delayBetweenRings, 30);

    const startAnimation = () => {
      const animate = (now) => {
        if (cancelled) return;
        if (lastRingTime === null) lastRingTime = now;
        const elapsed = now - lastRingTime;
        ringProgress = Math.min(elapsed / ringDuration, 1);
        drawFrame(canvas, ctx, dpr, canvasSize, completedRings, ringProgress, now);
        if (ringProgress >= 1 && completedRings < numRings) {
          completedRings++;
          lastRingTime = now;
          ringProgress = 0;
        }
        stateRef.current.completedRings = completedRings;
        stateRef.current.animFrame = requestAnimationFrame(animate);
      };
      stateRef.current.animFrame = requestAnimationFrame(animate);
    };

    const timer = setTimeout(startAnimation, startDelay);
    return () => {
      cancelled = true;
      clearTimeout(timer);
      if (stateRef.current.animFrame) cancelAnimationFrame(stateRef.current.animFrame);
    };
  }, [numRings, animated, delayBetweenRings, canvasSize, showCounter, showPith, startDelay]);

  return <canvas ref={canvasRef} className={className} style={{ display: "block", background: "transparent" }} />;
}

// ── Specimen Canvas (with real image) ────────────────────────────
function SpecimenCanvas({ onPithSet, canvasRef: externalRef, width = 340, height = 320 }) {
  const canvasRef = externalRef || useRef(null);
  const [pith, setPith] = useState(null);
  const rippleRef = useRef([]);
  const animFrameRef = useRef(null);
  const imgRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = width + "px";
    canvas.style.height = height + "px";
    const ctx = canvas.getContext("2d");
    ctx.scale(dpr, dpr);

    const img = new Image();
    img.onload = () => {
      imgRef.current = img;
      render(ctx, width, height, null, 0);
    };
    img.src = F09D_SRC;

    let cancelled = false;
    let startTime = Date.now();

    const render = (ctx, w, h, pithPos, t) => {
      ctx.clearRect(0, 0, w, h);
      if (imgRef.current) {
        const img = imgRef.current;
        const scale = Math.min(w / img.width, h / img.height);
        const dw = img.width * scale;
        const dh = img.height * scale;
        const ox = (w - dw) / 2;
        const oy = (h - dh) / 2;
        ctx.drawImage(img, ox, oy, dw, dh);
        ctx.fillStyle = "rgba(0,0,0,0.18)";
        ctx.fillRect(0, 0, w, h);
        ctx.strokeStyle = "rgba(234,88,12,0.10)";
        ctx.setLineDash([4, 8]);
        ctx.lineWidth = 0.5;
        ctx.beginPath(); ctx.moveTo(w / 2, 0); ctx.lineTo(w / 2, h); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(0, h / 2); ctx.lineTo(w, h / 2); ctx.stroke();
        ctx.setLineDash([]);
      }
      if (pithPos) {
        const { x, y } = pithPos;
        const sz = 10;
        ctx.strokeStyle = "#ea580c";
        ctx.lineWidth = 1.5;
        ctx.beginPath(); ctx.moveTo(x - sz, y); ctx.lineTo(x - 4, y); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(x + 4, y); ctx.lineTo(x + sz, y); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(x, y - sz); ctx.lineTo(x, y - 4); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(x, y + 4); ctx.lineTo(x, y + sz); ctx.stroke();
        ctx.fillStyle = "#ea580c";
        ctx.shadowBlur = 10;
        ctx.shadowColor = "#ea580c";
        ctx.beginPath();
        ctx.arc(x, y, 3, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;
        const age = t - pithPos.time;
        for (let r = 0; r < 3; r++) {
          const delay = r * 300;
          const elapsed = Math.max(0, age - delay);
          const rad = (elapsed / 800) * 30;
          const opacity = Math.max(0, 1 - elapsed / 800);
          if (opacity > 0) {
            ctx.beginPath();
            ctx.arc(x, y, rad, 0, Math.PI * 2);
            ctx.strokeStyle = `rgba(234,88,12,${opacity * 0.7})`;
            ctx.lineWidth = 1;
            ctx.stroke();
          }
        }
      }
    };

    const loop = () => {
      if (cancelled) return;
      const ctx = canvas.getContext("2d");
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      render(ctx, width, height, pith, Date.now() - startTime);
      animFrameRef.current = requestAnimationFrame(loop);
    };
    animFrameRef.current = requestAnimationFrame(loop);

    return () => { cancelled = true; if (animFrameRef.current) cancelAnimationFrame(animFrameRef.current); };
  }, [width, height, pith]);

  const setPithAt = useCallback((x, y) => {
    const p = { x, y, time: Date.now() };
    setPith(p);
    if (onPithSet) onPithSet(x, y);
  }, [onPithSet]);

  useEffect(() => {
    if (externalRef) externalRef.setPithAt = setPithAt;
  }, [externalRef, setPithAt]);

  return (
    <canvas ref={canvasRef}
      style={{ display: "block", cursor: "crosshair", width, height }}
      onClick={e => {
        const rect = e.currentTarget.getBoundingClientRect();
        setPithAt(e.clientX - rect.left, e.clientY - rect.top);
      }}
    />
  );
}

