      if (!el) return;
      const r = el.getBoundingClientRect();
      await cursor.current.moveTo(r.left + r.width / 2, r.top + r.height / 2, 700);
      if (cancelled) return;
      await sleep(300);
      cursor.current.click(r.left + r.width / 2, r.top + r.height / 2);
      setSelectedSample("F09D");
      await sleep(800);
      setIsLoaded(true);
      await sleep(600);
      if (!proceedRef.current || cancelled) return;
      const pr = proceedRef.current.getBoundingClientRect();
      await cursor.current.moveTo(pr.left + pr.width / 2, pr.top + pr.height / 2, 600);
      await sleep(300);
      cursor.current.click(pr.left + pr.width / 2, pr.top + pr.height / 2);
