                <button style={{ ...S.mono, flex: 1, padding: "6px 0", fontSize: 9, letterSpacing: "0.15em", border: "2px solid #333", color: "#555", background: "transparent", cursor: "pointer" }}>[○ IMAGE CENTER]</button>
