function ExportButton({ label, sub, id }) {
  const [state, setState] = useState("idle");
  const handleClick = useCallback(() => {
    setState("loading");
    setTimeout(() => setState("done"), 1200);
  }, []);
  return (
    <motion.button id={id} onClick={handleClick}
      style={{
        ...S.mono, width: "100%", padding: "8px 6px", background: state === "done" ? "rgba(34,197,94,0.1)" : "transparent",
        border: state === "done" ? "2px solid #22c55e" : "2px solid #333",
        color: state === "done" ? "#22c55e" : state === "loading" ? "#ea580c" : "#888",
        fontSize: 9, letterSpacing: "0.12em", cursor: "pointer", textTransform: "uppercase",
        boxShadow: state === "done" ? "0 0 8px rgba(34,197,94,0.3)" : "none",
        display: "flex", flexDirection: "column", alignItems: "flex-start", gap: 2
      }}>
      <span>{state === "done" ? "✓ DOWNLOADED" : state === "loading" ? "GENERATING █" : label}</span>
      <span style={{ fontSize: 7, color: "#555", letterSpacing: "0.08em" }}>{sub}</span>
    </motion.button>
  );
}

